mapper.select:
SELECT tt.id, tt.name, tt.remark, tt.flow_id, tt.execute_type, tt.cron, tt.failure_policy, tt.notify_policy, tt.enable, tt.status, tt.reason, tt.execute_time, tt.created_time, tf.name AS flow_name, tg.id AS group_id, tg.name AS group_name FROM trans_task AS tt LEFT JOIN trans_flow AS tf ON tt.flow_id = tf.id AND tf.deleted = 0 LEFT JOIN trans_group AS tg ON tf.group_id = tg.id AND tg.deleted = 0 WHERE tt.deleted = 0
AND tf.group_id IN
#{groupId}
AND tt.name LIKE CONCAT('%', #{params.name}, '%')
AND tt.status = #{params.status}
AND tt.enable = #{params.enable}
ORDER BY tt.created_time DESC
